def solve(rooms: List[List[int]]) -> None:
    if not rooms: return
    rows, cols = len(rooms), len(rooms[0])
    q = collections.deque()
    for r in range(rows):
        for c in range(cols):
            if rooms[r][c] == 0:
                q.append((r, c))
    dist = 0
    while q:
        for i in range(len(q)):
            r, c = q.popleft()
            directions = [[1,0], [-1,0], [0,1], [0,-1]]
            for dr, dc in directions:
                nr, nc = r+dr, c+dc
                if nr in range(rows) and nc in range(cols) and rooms[nr][nc] == 2147483647:
                    rooms[nr][nc] = rooms[r][c] + 1
                    q.append((nr, nc))

